class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    """
    Envoy External Authorization gRPC service implementation.
    Receives CheckRequest and returns CheckResponse.
    """

    def __init__(self, policy: AuthPolicy = None):
        self.policy = policy or AuthPolicy()
        logger.info("Authorization service initialized")

    def Check(self, request, context):
        """
        Main authorization check method.
        Called by Envoy for each request that needs authorization.
        """
        try:
            # Extract request attributes
            attrs = request.attributes
            http_request = attrs.request.http

            # Extract headers into a simple dict
            headers = dict(http_request.headers)

            # Get request metadata
            path = http_request.path
            method = http_request.method
            host = http_request.host
            scheme = http_request.scheme
            protocol = http_request.protocol

            # Get source/destination info
            source_ip = ""
            if attrs.source and attrs.source.address and attrs.source.address.socket_address:
                source_ip = attrs.source.address.socket_address.address

            destination_ip = ""
            if attrs.destination and attrs.destination.address and attrs.destination.address.socket_address:
                destination_ip = attrs.destination.address.socket_address.address

            logger.info(
                f"CheckRequest: {method} {scheme}://{host}{path} "
                f"from={source_ip} to={destination_ip} "
                f"protocol={protocol}"
            )
            logger.debug(f"Request headers: {json.dumps(headers, indent=2)}")

            # Make authorization decision
            decision = self.policy.authorize(headers, path, method, source_ip)

            # Build the CheckResponse
            if decision.allowed:
                return self._build_ok_response(decision)
            else:
                return self._build_denied_response(decision)

        except Exception as e:
            logger.error(f"Error processing check request: {e}", exc_info=True)
            # On error, deny by default (fail-closed)
            return self._build_denied_response(
                AuthorizationDecision(
                    allowed=False,
                    status_code=500,
                    message="Internal authorization error",
                )
            )

    def _build_ok_response(self, decision: AuthorizationDecision):
        """Build an OK (allowed) CheckResponse."""
        # Build headers to add to the upstream request
        headers_to_add = []
        for key, value in decision.headers_to_add.items():
            headers_to_add.append(
                base_pb2.HeaderValueOption(
                    header=base_pb2.HeaderValue(key=key, value=value),
                    append=False,  # Replace if exists
                )
            )

        ok_response = external_auth_pb2.OkHttpResponse(
            headers=headers_to_add,
            headers_to_remove=decision.headers_to_remove,
        )

        # Build dynamic metadata if present
        response = external_auth_pb2.CheckResponse(
            status=status_pb2.Status(code=code_pb2.OK),
            ok_response=ok_response,
        )

        # Add dynamic metadata for downstream filters
        if decision.dynamic_metadata:
            dynamic_metadata = struct_pb2.Struct()
            for key, value in decision.dynamic_metadata.items():
                if isinstance(value, list):
                    dynamic_metadata.fields[key].string_value = ','.join(str(v) for v in value)
                elif isinstance(value, (int, float)):
                    dynamic_metadata.fields[key].number_value = value
                elif isinstance(value, bool):
                    dynamic_metadata.fields[key].bool_value = value
                else:
                    dynamic_metadata.fields[key].string_value = str(value) if value else ''
            response.dynamic_metadata.CopyFrom(dynamic_metadata)

        logger.debug("Returning OK response")
        return response

    def _build_denied_response(self, decision: AuthorizationDecision):
        """Build a denied CheckResponse."""
        # Map status code to Envoy HTTP status
        http_status_map = {
            400: http_status_pb2.BadRequest,
            401: http_status_pb2.Unauthorized,
            403: http_status_pb2.Forbidden,
            404: http_status_pb2.NotFound,
            405: http_status_pb2.MethodNotAllowed,
            429: http_status_pb2.TooManyRequests,
            500: http_status_pb2.InternalServerError,
            503: http_status_pb2.ServiceUnavailable,
        }

        envoy_status_code = http_status_map.get(
            decision.status_code,
            http_status_pb2.Forbidden
        )

        # Build response headers
        response_headers = []
        response_headers.append(
            base_pb2.HeaderValueOption(
                header=base_pb2.HeaderValue(
                    key='content-type',
                    value='application/json'
                ),
                append=False,
            )
        )

        # Add any additional headers from the decision
        for key, value in decision.headers_to_add.items():
            response_headers.append(
                base_pb2.HeaderValueOption(
                    header=base_pb2.HeaderValue(key=key, value=value),
                    append=False,
                )
            )

        # Build the response body
        body = json.dumps({
            'error': decision.message,
            'status': decision.status_code,
            'timestamp': int(time.time()),
        })

        denied_response = external_auth_pb2.DeniedHttpResponse(
            status=http_status_pb2.HttpStatus(code=envoy_status_code),
            headers=response_headers,
            body=body,
        )

        # Map to gRPC status code
        grpc_code_map = {
            401: code_pb2.UNAUTHENTICATED,
            403: code_pb2.PERMISSION_DENIED,
            429: code_pb2.RESOURCE_EXHAUSTED,
            500: code_pb2.INTERNAL,
        }
        grpc_code = grpc_code_map.get(decision.status_code, code_pb2.PERMISSION_DENIED)

        response = external_auth_pb2.CheckResponse(
            status=status_pb2.Status(
                code=grpc_code,
                message=decision.message,
            ),
            denied_response=denied_response,
        )

        logger.debug(f"Returning denied response: {decision.status_code} {decision.message}")
        return response


