def serve():
    """Start the gRPC server."""
    # Create the authorization policy
    policy = AuthPolicy()

    # Create the gRPC server
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=MAX_WORKERS),
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 10000),
            ('grpc.keepalive_permit_without_calls', True),
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.http2.min_time_between_pings_ms', 10000),
        ],
    )

    # Register the authorization service
    auth_service = AuthorizationService(policy=policy)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_service, server)

    # Configure TLS if certificates are provided
    tls_cert_path = os.environ.get('TLS_CERT_PATH')
    tls_key_path = os.environ.get('TLS_KEY_PATH')
    tls_ca_path = os.environ.get('TLS_CA_PATH')

    listen_addr = f'[::]:{LISTEN_PORT}'

    if tls_cert_path and tls_key_path:
        logger.info("TLS enabled for gRPC server")
        with open(tls_cert_path, 'rb') as f:
            cert = f.read()
        with open(tls_key_path, 'rb') as f:
            key = f.read()

        ca_cert = None
        if tls_ca_path:
            with open(tls_ca_path, 'rb') as f:
                ca_cert = f.read()

        credentials = grpc.ssl_server_credentials(
            [(key, cert)],
            root_certificates=ca_cert,
            require_client_auth=bool(ca_cert),
        )
        server.add_secure_port(listen_addr, credentials)
        logger.info(f"Secure gRPC server listening on {listen_addr}")
    else:
        server.add_insecure_port(listen_addr)
        logger.info(f"Insecure gRPC server listening on {listen_addr}")

    # Start the server
    server.start()
    logger.info("Envoy External Authorization service started")
    logger.info(f"Configuration:")
    logger.info(f"  Port: {LISTEN_PORT}")
    logger.info(f"  Workers: {MAX_WORKERS}")
    logger.info(f"  API Keys configured: {len(VALID_API_KEYS)}")
    logger.info(f"  Auth rules configured: {len(AUTH_RULES)}")

    # Print Envoy configuration example
    print_envoy_config_example()

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        server.stop(grace=5)
        logger.info("Server stopped")


